#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
PUBSPEC = Path("pubspec.yaml")
HEALTH = Path("lib/system_health.dart")
VALIDATOR = Path("tools/validate_questions.py")
SMOKE_TEST = Path("test/system_smoke_test.dart")
WORKFLOW = Path(".github/workflows/quality-checks.yml")

HEALTH_B64 = """"""
VALIDATOR_B64 = """"""
TEST_B64 = """"""
WORKFLOW_B64 = """"""

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, PUBSPEC]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

question_status = subprocess.run(
    [
        "git",
        "status",
        "--porcelain",
        "--",
        "assets/questions.json",
    ],
    text=True,
    capture_output=True,
    check=True,
).stdout.strip()

if question_status:
    raise SystemExit(
        "assets/questions.json dosyasında yerel değişiklik var.\n"
        "Soru düzeltmelerini ayrı branch'te tutup main dalını "
        "temizledikten sonra bu paketi çalıştır."
    )

for path in [HEALTH, VALIDATOR, SMOKE_TEST, WORKFLOW]:
    if path.exists():
        raise SystemExit(
            f"Yeni paket dosyası zaten var: {path}"
        )

main = MAIN.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")

required_main = [
    "import 'dart:io';",
    "part 'social_features.dart';",
    "class GameSaveService",
    "static Future<SavedGame?> load() async",
    "await AppPreferencesService.initialize();",
    "SocialHomeButton(",
    "Bilgi Rotası • Sürüm 1.28",
]

for marker in required_main:
    if marker not in main:
        raise SystemExit(
            f"Beklenen main.dart bölümü bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(
    int,
    version_match.groups(),
)

if (major, minor) != (1, 28):
    raise SystemExit(
        "Bu paket 1.28.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.29.0+{build + 1}"

backup_dir = Path(tempfile.mkdtemp(
    prefix="bilgi_rotasi_system_health_"
))
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")

    for path in [
        HEALTH.parent,
        VALIDATOR.parent,
        SMOKE_TEST.parent,
        WORKFLOW.parent,
    ]:
        path.mkdir(parents=True, exist_ok=True)

    HEALTH.write_text(
        base64.b64decode(HEALTH_B64).decode("utf-8"),
        encoding="utf-8",
    )
    VALIDATOR.write_text(
        base64.b64decode(VALIDATOR_B64).decode("utf-8"),
        encoding="utf-8",
    )
    SMOKE_TEST.write_text(
        base64.b64decode(TEST_B64).decode("utf-8"),
        encoding="utf-8",
    )
    WORKFLOW.write_text(
        base64.b64decode(WORKFLOW_B64).decode("utf-8"),
        encoding="utf-8",
    )

    main = main.replace(
        "import 'dart:math';",
        "import 'dart:math';\n"
        "import 'dart:ui' as ui;",
        1,
    )

    main = main.replace(
        "part 'social_features.dart';",
        "part 'social_features.dart';\n"
        "part 'system_health.dart';",
        1,
    )

    main_start_marker = """Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();

  try {
    await SoundFx.initialize();"""

    if main_start_marker not in main:
        raise RuntimeError(
            "Teknik hata yakalama başlangıç noktası bulunamadı."
        )

    main = main.replace(
        main_start_marker,
        """Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();

  await AppErrorLogService.initialize();

  try {
    await SoundFx.initialize();""",
        1,
    )

    save_start = main.index("class GameSaveService")
    save_end = main.index("class CareerStats", save_start)
    save_block = main[save_start:save_end]

    save_write_marker = """      await _preferences.setString(
        _saveKey,
        jsonEncode(payload),
      );"""

    if save_write_marker not in save_block:
        raise RuntimeError(
            "Otomatik yedekleme kayıt noktası bulunamadı."
        )

    save_block = save_block.replace(
        save_write_marker,
        """      await GameRecoveryService.saveWithBackup(
        jsonEncode(payload),
      );""",
        1,
    )

    load_start = save_block.index(
        "  static Future<SavedGame?> load() async"
    )
    load_end = save_block.index(
        "\n  static Future<void> clear()",
        load_start,
    )
    load_block = save_block[load_start:load_end]

    load_catch_marker = """    } catch (_) {
      await clear();
      return null;
    }"""

    if load_catch_marker not in load_block:
        raise RuntimeError(
            "Bozuk kayıt kurtarma noktası bulunamadı."
        )

    load_block = load_block.replace(
        load_catch_marker,
        """    } catch (error, stack) {
      await AppErrorLogService.record(
        source: 'Kayıt yükleme',
        error: error,
        stack: stack,
      );

      final recovered =
          await GameRecoveryService.recover();

      if (recovered != null) {
        return recovered;
      }

      await clear();
      return null;
    }""",
        1,
    )

    save_block = (
        save_block[:load_start]
        + load_block
        + save_block[load_end:]
    )

    clear_start = save_block.index(
        "  static Future<void> clear()"
    )
    clear_end = save_block.index(
        "\n  static Map<String, dynamic> _playerToJson",
        clear_start,
    )
    clear_block = save_block[clear_start:clear_end]

    clear_marker = """      await _preferences.remove(_saveKey);"""

    if clear_marker not in clear_block:
        raise RuntimeError(
            "Kayıt yedeği temizleme noktası bulunamadı."
        )

    clear_block = clear_block.replace(
        clear_marker,
        """      await _preferences.remove(_saveKey);
      await GameRecoveryService.clearBackup();""",
        1,
    )

    save_block = (
        save_block[:clear_start]
        + clear_block
        + save_block[clear_end:]
    )

    main = (
        main[:save_start]
        + save_block
        + main[save_end:]
    )

    home_marker = """                SocialHomeButton(
                  questionBank: widget.questionBank,
                ),
                const SizedBox(height: 16),
                _buildNewGameCard(),"""

    if home_marker not in main:
        raise RuntimeError(
            "Ana ekran sistem sağlığı düğmesi ekleme noktası bulunamadı."
        )

    main = main.replace(
        home_marker,
        """                SocialHomeButton(
                  questionBank: widget.questionBank,
                ),
                const SizedBox(height: 10),
                SystemHealthHomeButton(
                  questionBank: widget.questionBank,
                ),
                const SizedBox(height: 16),
                _buildNewGameCard(),""",
        1,
    )

    main, version_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.28(?:\.\d+)?",
        "Bilgi Rotası • Sürüm 1.29",
        main,
        count=1,
    )

    if version_count != 1:
        raise RuntimeError(
            "Ana menü sürüm yazısı güncellenemedi."
        )

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "import 'dart:ui' as ui;",
            "part 'system_health.dart';",
            "AppErrorLogService.initialize",
            "GameRecoveryService.saveWithBackup",
            "GameRecoveryService.recover",
            "SystemHealthHomeButton(",
            "Bilgi Rotası • Sürüm 1.29",
        ],
        HEALTH: [
            "class AppErrorLogService",
            "class GameRecoveryService",
            "class QuestionHealthReport",
            "class SystemHealthScreen",
            "Performans Modunu Aç",
            "Kurtarma Yedeğini Geri Yükle",
        ],
        VALIDATOR: [
            "Bilgi Rotası soru bankası raporu",
            "VALID_DIFFICULTIES",
        ],
        SMOKE_TEST: [
            "Bilgi Rotası temel sistem testleri",
            "Meydan okuma kodu kayıpsız çözülür",
        ],
        WORKFLOW: [
            "Bilgi Rotasi Quality Checks",
            "flutter analyze",
            "flutter test",
        ],
        PUBSPEC: [f"version: {new_version}"],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")

        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: "
                    f"{path} / {marker}"
                )

    run([
        "python3",
        "tools/validate_questions.py",
    ])

    if shutil.which("dart"):
        run([
            "dart",
            "format",
            "lib/main.dart",
            "lib/system_health.dart",
            "test/system_smoke_test.dart",
        ])

    run(["git", "diff", "--check"])

    changed_paths = subprocess.check_output(
        ["git", "diff", "--name-only"],
        text=True,
    ).splitlines()

    if "assets/questions.json" in changed_paths:
        raise RuntimeError(
            "Güvenlik kontrolü: questions.json değişmiş görünüyor."
        )

    if shutil.which("flutter"):
        run(["flutter", "pub", "get"])
        run([
            "flutter",
            "analyze",
            "--no-fatal-infos",
        ])
        run(["flutter", "test"])
    else:
        print(
            "ℹ️ Flutter bu ortamda bulunamadı; "
            "analiz ve test GitHub Actions'ta çalışacak."
        )

    files_to_stage = [
        "lib/main.dart",
        "lib/system_health.dart",
        "tools/validate_questions.py",
        "test/system_smoke_test.dart",
        ".github/workflows/quality-checks.yml",
        "pubspec.yaml",
    ]

    if Path("pubspec.lock").exists():
        files_to_stage.append("pubspec.lock")

    run([
        "git",
        "add",
        *files_to_stage,
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError(
            "Commit edilecek değişiklik bulunamadı."
        )

    run([
        "git",
        "commit",
        "-m",
        "Sistem sagligi otomatik kurtarma ve kalite kontrolleri",
    ])
    committed = True

    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(
            backup_dir / "main.dart",
            MAIN,
        )
        shutil.copy2(
            backup_dir / "pubspec.yaml",
            PUBSPEC,
        )

        for path in [
            HEALTH,
            VALIDATOR,
            SMOKE_TEST,
            WORKFLOW,
        ]:
            if path.exists():
                path.unlink()

        reset_paths = [
            "lib/main.dart",
            "lib/system_health.dart",
            "tools/validate_questions.py",
            "test/system_smoke_test.dart",
            ".github/workflows/quality-checks.yml",
            "pubspec.yaml",
        ]

        if Path("pubspec.lock").exists():
            reset_paths.append("pubspec.lock")

        subprocess.run(
            [
                "git",
                "reset",
                "--",
                *reset_paths,
            ],
            check=False,
        )

        if shutil.which("flutter"):
            subprocess.run(
                ["flutter", "pub", "get"],
                check=False,
            )

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))

    if committed:
        print(
            "Commit oluşturuldu fakat push başarısız oldu. "
            "Tekrar dene: git push origin main"
        )
    else:
        print(
            "Özellik dosyaları önceki hâline otomatik döndürüldü."
        )

    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Uygulama içi Sistem Sağlığı ekranı eklendi.")
print("✅ Son 20 teknik hatayı saklayan hata günlüğü eklendi.")
print("✅ Kayıtlı oyun için otomatik yedek ve kurtarma eklendi.")
print("✅ Soru bankası kimliği, kategori sayımları ve yapısal tarama eklendi.")
print("✅ Tek dokunuşla Performans Modu ve önbellek temizleme eklendi.")
print("✅ Salt-okunur Python soru doğrulayıcısı eklendi.")
print("✅ Flutter temel sistem testleri eklendi.")
print("✅ GitHub Actions kalite kontrolü eklendi.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
